preToolUse.powershell:
$inputText = [Console]::In.ReadToEnd()
$logLevel = if ($env:VSTACK_HOOKS_LOG_LEVEL) { $env:VSTACK_HOOKS_LOG_LEVEL } else { 'minimal' }
$logRoot = if ($env:VSTACK_HOOK_LOG_DIR) { $env:VSTACK_HOOK_LOG_DIR } else { '.vstack/logs' }
$logDir = Join-Path $logRoot (Get-Date).ToUniversalTime().ToString('yyyyMMdd')
New-Item -ItemType Directory -Force -Path $logDir | Out-Null
if ($logLevel -eq 'off') {
  exit 0
}
if ($logLevel -eq 'verbose') {
  Add-Content -Path (Join-Path $logDir 'hook-tool-use.log') -Value $inputText
  exit 0
}
$scriptStart = Get-Date
function Get-PathValue {
  param([object]$Object, [string]$Path)
  $current = $Object
  foreach ($part in $Path.Split('.')) {
    if ($null -eq $current) {
      return $null
    }
    $prop = $current.PSObject.Properties[$part]
    if ($null -eq $prop) {
      return $null
    }
    $current = $prop.Value
  }
  return $current
}
function Get-FirstString {
  param([object]$Object, [string[]]$Paths)
  foreach ($path in $Paths) {
    $value = Get-PathValue -Object $Object -Path $path
    if ($null -ne $value -and [string]$value -ne '') {
      return [string]$value
    }
  }
  return $null
}
$toolName = 'unknown'
$toolCallId = 'unknown'
try {
  $payload = $inputText | ConvertFrom-Json -ErrorAction Stop
  $toolNameCandidate = Get-FirstString -Object $payload -Paths @('toolName', 'tool_name', 'recipient_name', 'tool.name', 'toolCall.name', 'toolCall.toolName', 'tool_call.name', 'tool_call.tool_name')
  if ($toolNameCandidate) {
    $toolName = $toolNameCandidate
  }
  $toolCallIdCandidate = Get-FirstString -Object $payload -Paths @('toolCallId', 'tool_call_id', 'callId', 'call_id', 'toolCall.id', 'tool_call.id')
  if ($toolCallIdCandidate) {
    $toolCallId = $toolCallIdCandidate
  }
} catch {
}
if ($toolName -eq 'unknown') {
  $toolNameMatch = [regex]::Match($inputText, '[A-Za-z_][A-Za-z0-9_]*\.[A-Za-z_][A-Za-z0-9_]*')
  if ($toolNameMatch.Success) {
    $toolName = $toolNameMatch.Value
  }
}
$hookExecutionMs = [int][Math]::Max(0, ((Get-Date) - $scriptStart).TotalMilliseconds)
$record = @{
  timestamp = (Get-Date).ToUniversalTime().ToString('o')
  event = 'preToolUse'
  tool_name = $toolName
  tool_call_id = $toolCallId
  size_bytes = $inputText.Length
  estimated_tokens = [int][math]::Ceiling($inputText.Length / 4.0)
  hook_execution_ms = $hookExecutionMs
} | ConvertTo-Json -Compress
Add-Content -Path (Join-Path $logDir 'hook-tool-use.log') -Value $record

